命令zig run my_code.zig将编译并立即运行您的Zigprogram。这些单元格中的每一个都包含一个可以尝试运行的zig程序（其中一些包含编译时错误，可以将其注释掉以进行播放）
   //注释看起来像这样，然后转到pub fn main（）行的末尾void {}
 您可以使用内置的@import并将命名空间分配给const值，从标准库中进行导入。必须为zig中的几乎所有内容明确分配其标识符。您也可以这样导入其他zig文件，以及使用@cImport以类似方式导入C文件。
    const std = @import（＆＃34; std＆＃34;）; pub fn main（）void {var x：i32 = 47; //声明＆＃34; x＆＃34; i32类型的值为47。std.debug。 print（＆＃34; x：{} \ n＆＃34 ;,。{x}）;}
  pub fn main（）void {const x：i32 = 47; x = 42； //错误：无法分配给常量}
 Zig非常挑剔，不会让您在外部范围内隐藏标识符，以免引起混淆：
 const x：i32 = 47; pub fn main（）void {var x：i32 = 42; //错误：重新定义＆＃39; x＆＃39;} 
全局作用域中的常量默认情况下是编译时＆＃34; comptime＆＃34;值，如果您省略类型，则它们是comptime类型的，并且可以转换为您的运行时值的运行时类型。
 const x：i32 = 47;常数y = -47; // comptime整数。 pub fn main（）void {var a：i32 = y; //将comptime常数强制转换为正确的类型var b：i64 = y; //将comptime常数强制转换为正确的类型var c：u32 = y; //错误：无法将负值-47转换为无符号整数}
 如果稍后要设置它，则可以明确地选择使其保持未定义状态，但是如果您尝试使用它，zig将会出错。
 pub fn main（）void {var x：i32 = undefined; foo（x）; //错误：使用未声明的标识符＆＃39; foo＆＃39;}
 在某些情况下，zig将允许您省略类型信息（如果可以确定的话）。
 const std = @import（＆＃34; std＆＃34;）; pub fn main（）void {var x：i32 = 47; var y：i32 = 47; var z = x + y; //声明z并将其设置为94。std.debug。 print（＆＃34; z：{} \ n＆＃34 ;,。{z}）;}
  pub fn main（）void {var x = 47; //错误：类型为＆＃39; comptime_int＆＃39;的变量必须为const或comptime} 
这是一个不返回任何内容的函数（foo）。 pub关键字表示该函数可从当前作用域导出，这就是为什么main必须是pub的原因。 Youcall的功能与大多数编程语言相同：
 const std = @import（＆＃34; std＆＃34;）; fn foo（）void {std.debug。 print（＆＃34; foo！\ n＆＃34 ;,。{}）; //可选：return;} pub fn main（）void {foo（）;}
  const std = @import（＆＃34; std＆＃34;）; fn foo（）i32 {return 47;} pub fn main（）void {var result = foo（）;标准调试。 print（＆＃34; foo：{} \ n＆＃34 ;,。{result}）;}
  fn foo（）i32 {return 47;} pub fn main（）void {foo（）; //错误：表达式值被忽略}
    const std = @import（＆＃34; std＆＃34;）; fn foo（x：i32）void {std.debug。 print（＆＃34; foo param：{} \ n＆＃34 ;,。{x}）;} pub fn main（）void {foo（47）;}
  可以通过使用const关键字为结构命名来声明结构，它们可以不按顺序分配，也可以通过使用通常的点语法取消引用来使用它们。
 const std = @import（＆＃34; std＆＃34;）; const Vec2 = struct {x：f64，y：f64}; pub fn main（）void {var v = Vec2 {.y = 1.0，.x = 2.0};标准调试。 print（＆＃34; v：{} \ n＆＃34 ;,。{v}）;} 
结构可以具有默认值；结构也可以是匿名的，并且可以强制转换为另一个结构，只要可以将所有值都标明：
 const std = @import（＆＃34; std＆＃34;）; const Vec3 = struct {x：f64 = 0.0，y：f64，z：f64}; pub fn main（）void {var v：Vec3 =。{。y = 0.1，.z = 0.2}; //好的var w：Vec3 =。{。y = 0.1}; //错误：缺少字段：＆＃39; z＆＃39;标准调试。 print（＆＃34; v：{} \ n＆＃34 ;,。{v}）;}
 您可以将函数放入结构中以使其像OOP样式的对象一样工作。第一个参数是指向对象的指针，可以称为＆＃34; Object-style＆＃34 ;，类似于Python具有自参数化成员函数的方式。典型的约定是通过调用变量self使这一点变得显而易见。
 const std = @import（＆＃34; std＆＃34;）; const LikeAnObject = struct {值：i32，fn print（self：* LikeAnObject）void {std.debug。 print（＆＃34; value：{} \ n＆＃34 ;,。{self.value}）; }}; pub fn main（）void {var obj = LikeAnObject {.value = 47};对象打印（）;}
  通过使用const关键字将枚举组分配为类型来声明枚举。
  您可以将Enum的值设置为整数，但不会自动强制转换，必须使用@enumToInt或@intToEnum进行转换。
 const std = @import（＆＃34; std＆＃34;）; const EnumType =枚举{EnumOne，EnumTwo，EnumThree = 3}; pub fn main（）void {std.debug。 print（＆＃34; One：{} \ n＆＃34 ;,。{EnumType.EnumOne}）;标准调试。 print（＆＃34; Two ?: {} \ n＆＃34 ;,。{EnumType.EnumTwo == .EnumTwo}）;标准调试。 print（＆＃34; Three ?: {} \ n＆＃34 ;,。{@enumToInt（EnumType.EnumThree）== 3}）;} 
zig具有数组，它们是具有编译时已知长度的连续内存。您可以通过预先声明类型并提供值列表来对其进行初始化。您可以使用数组的len字段访问长度。
   const std = @import（＆＃34; std＆＃34;）; pub fn main（）void {var array：[3] u32 = [3] u32 {47，47，47}; //也有效：// var array = [_] u32 {47，47，47}; var invalid = array [4]; //错误：索引4在大小为3的数组之外。std.debug。 print（＆＃34; array [0]：{} \ n＆＃34 ;,。{array [0]}）;标准调试。 print（＆＃34; length：{} \ n＆＃34 ;,。{array.len}）;}
 zig还具有切片，这些切片具有运行时已知的长度。您可以使用切片操作从数组或其他切片构造切片。与数组类似，切片具有一个len字段，该字段告诉您其长度。
   尝试访问超出分片范围的操作会导致运行时恐慌（这意味着您的程序将崩溃）。
 const std = @import（＆＃34; std＆＃34;）; pub fn main（）void {var array：[3] u32 = [_] u32 {47，47，47}; var slice：[] u32 = array [0 ..2]; //也有效：// var slice = array [0..2]; var invalid = slice [3]; //恐慌：索引超出标准std.debug。 print（＆＃34; slice [0]：{} \ n＆＃34 ;,。{slice [0]}）;标准调试。 print（＆＃34; length：{} \ n＆＃34 ;,。{slice.len}）;}
 顺便说一句，我们已经将该东西传递给了std.debug.print的第二个参数匿名数组。在编译时，将分析参数的内容和类型，并将其匹配到您提供的（编译时）格式字符串，并且show zig知道如何使打印内容漂亮。
 const std = @import（＆＃34; std＆＃34;）; pub fn main（）void {std.debug。 print（＆＃34; {} \ n＆＃34 ;,。{1，2}）; ＃错误：未使用的参数} 
字符串文字是以NULL终止的utf8编码的const u8字节数组。 Unicode字符仅允许在字符串文字和注释中使用。
   const std = @import（＆＃34; std＆＃34;）; const string =＆＃34; hello世界＆＃34 ;; const world =＆＃34; world＆＃34 ;; pub fn main（）void {var slice：[] const u8 = string [0 ..5];标准调试。 print（＆＃34; string {} \ n＆＃34 ;,。{string}）;标准调试。 print（＆＃34; length {} \ n＆＃34 ;,。{world.len}）;标准调试。 print（＆＃34; null {} \ n＆＃34 ;,。{world [5]}）;标准调试。 print（＆＃34; slice {} \ n＆＃34 ;,。{slice}）;标准调试。 print（＆＃34; huh？{} \ n＆＃34 ;,。{string [0 ..7]}）;}
  const std = @import（＆＃34; std＆＃34;）; fn foo（）[] const u8 {//注意函数返回一个切片return＆＃34; foo＆＃34 ;; //但这是一个const数组。} pub fn main（）void {std.debug。 print（＆＃34; foo：{} \ n＆＃34 ;,。{foo（）}）;}
   const std = @import（＆＃34; std＆＃34;）; fn foo（v：i32）[] const u8 {if（v＆lt; 0）{return＆＃34; negative＆＃34 ;; } else {return＆＃34; non-negative＆＃34 ;; }} pub fn main（）void {std.debug。 print（＆＃34; positive {} \ n＆＃34 ;,。{foo（47）}）;标准调试。 print（＆＃34; negative {} \ n＆＃34 ;,。{foo（-47）}）;}
  const std = @import（＆＃34; std＆＃34;）; fn foo（v：i32）[] const u8 {开关（v）{0 =＆gt;返回＆＃34;零＆＃34;否则=＆gt;返回＆＃34;非零＆＃34; }} pub fn main（）void {std.debug。 print（＆＃34; 47 {} \ n＆＃34 ;,。{foo（47）}）;标准调试。 print（＆＃34; 0 {} \ n＆＃34 ;,。{foo（0）}）;}
  const std = @import（＆＃34; std＆＃34;）; pub fn main（）void {var array = [_] i32 {47，48，49};为（数组）|价值| {标准调试。 print（＆＃34; array {} \ n＆＃34 ;,。{value}）; }（数组）|值，索引| {标准调试。 print（＆＃34; array {}：{} \ n＆＃34 ;,。{index，value}）; } var slice = array [0 ..2];为（切片）|价值| {标准调试。 print（＆＃34; slice {} \ n＆＃34 ;,。{value}）; }（切片）|值，索引| {标准调试。 print（＆＃34; slice {}：{} \ n＆＃34 ;,。{index，value}）; }}
  const std = @import（＆＃34; std＆＃34;）; pub fn main（）void {var array = [_] i32 {47，48，49}; var索引：u32 = 0; while（index＆lt; 2）{std.debug。 print（＆＃34; value：{} \ n＆＃34 ;,。{array [index]}）;索引+ = 1; }} 
错误是特殊的联合类型，您表示函数可以通过加前缀来出错！到前面。您只需简单地将其返回就可以抛出错误，就像正常返回一样。
 const MyError = error {GenericError，//只是标识符列表，例如枚举。 OtherError}; pub fn main（）！ void {return MyError.GenericError;}
 如果编写的函数可能出错，则必须决定在返回时如何处理。 try是两个很常见的选项，它们非常懒惰，它们只是将错误转发为函数的错误。 catch可显式处理错误。
  const std = @import（＆＃34; std＆＃34;）; const MyError = error {GenericError}; fn foo（v：i32）！ i32 {if（v == 42）return MyError.GenericError; return v;} pub fn main（）！ void {// //捕获陷阱并处理冒泡的错误_ = foo（42）catch | err | {标准调试。 print（＆＃34; error：{} \ n＆＃34 ;,。{err}）; }; //尝试不要在这里被激活。标准调试。 print（＆＃34; foo：{} \ n＆＃34 ;,。{try foo（47）}）; //这最终将导致main打印错误跟踪并返回非零_ = try foo（42）;}
  const std = @import（＆＃34; std＆＃34;）; const MyError = error {GenericError}; fn foo（v：i32）！ i32 {if（v == 42）return MyError.GenericError; return v;} //注意，wrap_foo没有错误是安全的！因为//我们处理所有情况，并且不返回错误。 fn wrap_foo（v：i32）void {if（foo（v））|价值| {标准调试。 print（＆＃34; value：{} \ n＆＃34 ;,。{value}）; } else |错误| {标准调试。 print（＆＃34; error：{} \ n＆＃34 ;,。{err}）; }} pub fn main（）void {wrap_foo（42）; wrap_foo（47）;}
    这是一个多重调度的示例（尽管您已经在std.debug.print中看到了这一点，也许现在您可以想象它是如何实现的：
 const std = @import（＆＃34; std＆＃34;）; fn foo（x：anytype）@TypeOf（x）{//注意，此if语句发生在编译时，而不是运行时。如果（@TypeOf（x）== i64）{返回x + 2; } else {return 2 * x; }} pub fn main（）void {var x：i64 = 47; var y：i32 = 47;标准调试。 print（＆＃34; i64-foo：{} \ n＆＃34 ;,。{foo（x）}）;标准调试。 print（＆＃34; i32-foo：{} \ n＆＃34 ;,。{foo（y）}）;} 
const std = @import（＆＃34; std＆＃34;）; fn Vec2Of（comptime T：type）type {return struct {x：T，y：T};} const V2i64 = Vec2Of（i64）; const V2f64 = Vec2Of（f64）; pub fn main（）void {var vi = V2i64 {.x = 47，.y = 47}; var vf = V2f64 {.x = 47.0，.y = 47.0}; 标准调试。 print（＆＃34; i64 vector：{} \ n＆＃34 ;,。{vi}）; 标准调试。 print（＆＃34; f64 vector：{} \ n＆＃34 ;,。{vf}）;}  就是这样！ 现在，您知道了相当不错的Zig。 我没有涉及的一些（非常重要）的事情包括：

note_en:
the command  zig run my_code.zig will compile and immediately run your Zigprogram. Each of these cells contains a zig program that you can try to run(some of them contain compile-time errors that you can comment out to playwith)
   // comments look like this and go to the end of the line pub  fn  main()  void {}
 You can import from the standard library by using the  @import builtin andassigning the namespace to a const value. Almost everything in zig must beexplicitly assigned its identifier. You can also import other zig files thisway, and C files in a similar fashion with  @cImport.
    const std  =  @import( &#34;std&#34;); pub  fn  main()  void {  var  x:  i32  =  47;  // declares &#34;x&#34; of type i32 to be 47. std.debug. print( &#34;x: {} \n&#34;, .{x});}
  pub  fn  main()  void {  const  x:  i32  =  47; x  =  42;  // error: cannot assign to constant}
 Zig is very picky and will NOT let you shadow identifiers from anoutside scope, to keep you from being confused:
 const  x:  i32  =  47; pub  fn  main()  void {  var  x:  i32  =  42;  // error: redefinition of &#39;x&#39;}
 Constants in the global scope are by default compile-time &#34;comptime&#34; values,and if you omit the type they are comptime typed and can turn intoruntime types for your runtime values.
 const  x:  i32  =  47; const y  =  -47;  // comptime integer. pub  fn  main()  void {  var  a:  i32  = y;  // comptime constant coerced into correct type  var  b:  i64  = y;  // comptime constant coerced into correct type  var  c:  u32  = y;  // error: cannot cast negative value -47 to unsigned integer}
 You can explicitly choose to leave it undefined if it will get set later,but zig will error if you try to use it.
 pub  fn  main()  void {  var  x:  i32  =  undefined;  foo(x);  // error: use of undeclared identifier &#39;foo&#39;}
 In some cases, zig will let you omit the type information if it can figureit out.
 const std  =  @import( &#34;std&#34;); pub  fn  main()  void {  var  x:  i32  =  47;  var  y:  i32  =  47;  var z  = x  + y;  // declares z and sets it to 94. std.debug. print( &#34;z: {} \n&#34;, .{z});}
  pub  fn  main()  void {  var x  =  47;  // error: variable of type &#39;comptime_int&#39; must be const or comptime}
  Here&#39;s a function ( foo) that returns nothing. The  pub keyword means that thefunction is exportable from the current scope, which is why main must be  pub. Youcall functions just as you would in most programming languages:
 const std  =  @import( &#34;std&#34;); fn  foo()  void { std.debug. print( &#34;foo! \n&#34;, .{});  //optional:  return;} pub  fn  main()  void {  foo();}
  const std  =  @import( &#34;std&#34;); fn  foo()  i32 {  return  47;} pub  fn  main()  void {  var result  =  foo(); std.debug. print( &#34;foo: {} \n&#34;, .{result});}
  fn  foo()  i32 {  return  47;} pub  fn  main()  void {  foo();  // error: expression value is ignored}
    const std  =  @import( &#34;std&#34;); fn  foo( x:  i32)  void { std.debug. print( &#34;foo param: {} \n&#34;, .{x});} pub  fn  main()  void {  foo( 47);}
  structs are declared by assigning them a name using the const keyword,they can be assigned out of order, and they can beused by dereferencing with the usual dot syntax.
 const std  =  @import( &#34;std&#34;); const  Vec2  =  struct{  x:  f64,  y:  f64}; pub  fn  main()  void {  var v  =  Vec2{.y  =  1.0, .x  =  2.0}; std.debug. print( &#34;v: {} \n&#34;, .{v});}
 structs can have default values; structs can also be anonymous, andcan coerce into another struct so long as all of the values can befigured out:
 const std  =  @import( &#34;std&#34;); const  Vec3  =  struct{  x:  f64  =  0.0,  y:  f64,  z:  f64}; pub  fn  main()  void {  var  v:  Vec3  = .{.y  =  0.1, .z  =  0.2};  // ok  var  w:  Vec3  = .{.y  =  0.1};  // error: missing field: &#39;z&#39; std.debug. print( &#34;v: {} \n&#34;, .{v});}
 You can drop functions into an struct to make it work like a OOP-style object.There is syntactic sugar where if you make the functions&#39; first parameter bea pointer to the object, it can be called &#34;Object-style&#34;, similar to how Pythonhas the self-parametered member functions. The typical convention is to make thisobvious by calling the variable self.
 const std  =  @import( &#34;std&#34;); const  LikeAnObject  =  struct{  value:  i32,  fn  print( self:  * LikeAnObject)  void { std.debug. print( &#34;value: {} \n&#34;, .{self.value}); }}; pub  fn  main()  void {  var obj  =  LikeAnObject{.value  =  47}; obj. print();}
  Enums are declared by assigning the group of enums as a type using theconst keyword.
  You can set the value of an Enum to an integer, but it does not automaticallycoerce, you have to use  @enumToInt or  @intToEnum to do conversions.
 const std  =  @import( &#34;std&#34;); const  EnumType  =  enum{ EnumOne, EnumTwo, EnumThree  =  3}; pub  fn  main()  void { std.debug. print( &#34;One: {} \n&#34;, .{EnumType.EnumOne}); std.debug. print( &#34;Two?: {} \n&#34;, .{EnumType.EnumTwo  ==  .EnumTwo}); std.debug. print( &#34;Three?: {} \n&#34;, .{ @enumToInt(EnumType.EnumThree)  ==  3});}
  zig has Arrays, which are contiguous memory with compile-time known length.You can initialize them by declaring the type up front and providing the listof values. You can access the length with the  len field of the array.
   const std  =  @import( &#34;std&#34;); pub  fn  main()  void {  var  array: [ 3] u32  = [ 3] u32{ 47,  47,  47};  // also valid:  // var array = [_]u32{47, 47, 47};  var invalid  = array[ 4];  // error: index 4 outside array of size 3. std.debug. print( &#34;array[0]: {} \n&#34;, .{array[ 0]}); std.debug. print( &#34;length: {} \n&#34;, .{array.len});}
 zig also has slices, which are have run-time known length. You can constructslices from arrays or other slices using the slicing operation. Similarly toarrays, slices have a len field which tells you its length.
   Attempting to access beyond the range of the slice is a runtime panic (this meansyour program will crash).
 const std  =  @import( &#34;std&#34;); pub  fn  main()  void {  var  array: [ 3] u32  = [ _] u32{ 47,  47,  47};  var  slice: [] u32  = array[0 ..2];  // also valid:  // var slice = array[0..2];  var invalid  = slice[ 3];  // panic: index out of bounds std.debug. print( &#34;slice[0]: {} \n&#34;, .{slice[ 0]}); std.debug. print( &#34;length: {} \n&#34;, .{slice.len});}
 By the way, that thing we&#39;ve been passing into the std.debug.print&#39;s second parameteran  anonymous array. at compile time, the contents and types of the parameters areanalyzed and matched up to the (compile time) format string that you provided, and that&#39;show zig knows how to make the contents of the print pretty.
 const std  =  @import( &#34;std&#34;); pub  fn  main()  void { std.debug. print( &#34;{} \n&#34;, .{ 1,  2}); #  error: Unused arguments}
 string literals are null-terminated utf-8 encoded arrays of  const u8 bytes. Unicode characters are only allowed in string literals and comments.
   const std  =  @import( &#34;std&#34;); const string  =  &#34;hello 世界&#34;; const world  =  &#34;world&#34;; pub  fn  main()  void {  var  slice: [] const  u8  = string[0 ..5]; std.debug. print( &#34;string {} \n&#34;, .{string}); std.debug. print( &#34;length {} \n&#34;, .{world.len}); std.debug. print( &#34;null {} \n&#34;, .{world[ 5]}); std.debug. print( &#34;slice {} \n&#34;, .{slice}); std.debug. print( &#34;huh? {} \n&#34;, .{string[0 ..7]});}
  const std  =  @import( &#34;std&#34;); fn  foo() [] const  u8 {  // note function returns a slice  return  &#34;foo&#34;;  // but this is a const array.} pub  fn  main()  void { std.debug. print( &#34;foo: {} \n&#34;, .{ foo()});}
   const std  =  @import( &#34;std&#34;); fn  foo( v:  i32) [] const  u8 {  if (v  &lt;  0) {  return  &#34;negative&#34;; }  else {  return  &#34;non-negative&#34;; }} pub  fn  main()  void { std.debug. print( &#34;positive {} \n&#34;, .{ foo( 47)}); std.debug. print( &#34;negative {} \n&#34;, .{ foo( -47)});}
  const std  =  @import( &#34;std&#34;); fn  foo( v:  i32) [] const  u8 {  switch (v) {  0  = &gt;  return  &#34;zero&#34;,  else  = &gt;  return  &#34;nonzero&#34; }} pub  fn  main()  void { std.debug. print( &#34;47 {} \n&#34;, .{ foo( 47)}); std.debug. print( &#34;0 {} \n&#34;, .{ foo( 0)});}
